    10→
    11→// Client is a thin HTTP wrapper for the Changelogue REST API.
    12→type Client struct {
    13→	BaseURL    string
    14→	APIKey     string
    15→	HTTPClient *http.Client
    16→}
    17→
    18→// NewClient creates a new API client.
    19→func NewClient(baseURL, apiKey string) *Client {
    20→	return &Client{
    21→		BaseURL: baseURL,
    22→		APIKey:  apiKey,
    23→		HTTPClient: &http.Client{
    24→			Timeout: 30 * time.Second,
    25→		},
    26→	}
    27→}
    28→
    29→func (c *Client) do(method, path string, body any) (*http.Response, error) {
    30→	var buf *bytes.Buffer
    31→	if body != nil {
    32→		buf = new(bytes.Buffer)
    33→		if err := json.NewEncoder(buf).Encode(body); err != nil {
    34→			return nil, fmt.Errorf("encoding request body: %w", err)
    35→		}
    36→	}
    37→
    38→	var req *http.Request
    39→	var err error
    40→	if buf != nil {
    41→		req, err = http.NewRequest(method, c.BaseURL+path, buf)
    42→	} else {
    43→		req, err = http.NewRequest(method, c.BaseURL+path, nil)
    44→	}
    45→	if err != nil {
    46→		return nil, fmt.Errorf("creating request: %w", err)
    47→	}
    48→
    49→	if c.APIKey != "" {
    50→		req.Header.Set("Authorization", "Bearer "+c.APIKey)
    51→	}
    52→	if body != nil {
    53→		req.Header.Set("Content-Type", "application/json")
    54→	}
    55→
    56→	return c.HTTPClient.Do(req)
    57→}
    58→
    59→// Get sends a GET request to the given API path.
    60→func (c *Client) Get(path string) (*http.Response, error) {
    61→	return c.do(http.MethodGet, path, nil)
    62→}
    63→
    64→// Post sends a POST request with a JSON body.
    65→func (c *Client) Post(path string, body any) (*http.Response, error) {
    66→	return c.do(http.MethodPost, path, body)
    67→}
    68→
    69→// Put sends a PUT request with a JSON body.
    70→func (c *Client) Put(path string, body any) (*http.Response, error) {
    71→	return c.do(http.MethodPut, path, body)
    72→}
    73→
    74→// Delete sends a DELETE request.
    75→func (c *Client) Delete(path string) (*http.Response, error) {
    76→	return c.do(http.MethodDelete, path, nil)
    77→}
    78→
