    18→			river.QueueDefault: {MaxWorkers: 100},
    19→		}
    20→	}
    21→	if len(periodicJobs) > 0 {
    22→		config.PeriodicJobs = periodicJobs
    23→	}
    24→	return river.NewClient(riverpgxv5.New(pool), config)
