    19→// ProcessResults persists raw ingestion results via the store.
    20→// Duplicate releases (unique constraint violations) are logged and skipped, not fatal.
    21→func (s *Service) ProcessResults(ctx context.Context, sourceID string, sourceName string, results []IngestionResult) error {
    22→	for _, r := range results {
