    26→	EnqueueAgentRun(ctx context.Context, projectID, trigger, version string) error
    27→	CreateReleaseTodo(ctx context.Context, releaseID string) (string, error)
    28→	HasReleaseGate(ctx context.Context, projectID string) (bool, error)
    29→}
    30→
    31→// NotifyWorker is a River worker that processes NotifyJobArgs.
    32→// It looks up the release, finds all source-level subscriptions, resolves
    33→// the notification channel for each, and dispatches via the appropriate sender.
    34→// After sending notifications, it checks the project's agent rules and
    35→// auto-triggers an agent run if the version criteria are met.
    36→type NotifyWorker struct {
    37→	river.WorkerDefaults[queue.NotifyJobArgs]
    38→	store     NotifyStore
    39→	senders   map[string]Sender
    40→	publicURL string // base URL for internal Changelogue links (e.g. "https://changelogue.example.com")
    41→}
    42→
    43→// NewSenders returns the default sender map for all notification channel types.
    44→func NewSenders() map[string]Sender {
    45→	return map[string]Sender{
    46→		"webhook": &WebhookSender{Client: &http.Client{Timeout: 10 * time.Second}},
    47→		"slack":   &SlackSender{Client: &http.Client{Timeout: 10 * time.Second}},
    48→		"discord": &DiscordSender{Client: &http.Client{Timeout: 10 * time.Second}},
    49→		"email":   &EmailSender{},
    50→	}
    51→}
    52→
    53→// NewNotifyWorker creates a NotifyWorker with default senders for webhook, Slack, and Discord.
    54→func NewNotifyWorker(store NotifyStore, publicURL string) *NotifyWorker {
    55→	return &NotifyWorker{
    56→		store:     store,
    57→		senders:   NewSenders(),
    58→		publicURL: strings.TrimRight(publicURL, "/"),
    59→	}
    60→}
    61→
    62→// VersionPassesFilter returns true if the version string passes the source's
    63→// include/exclude regex filters. When both are nil the version always passes.
    64→func VersionPassesFilter(version string, include, exclude *string) bool {
    65→	if include != nil && *include != "" {
    66→		matched, err := regexp.MatchString(*include, version)
    67→		if err != nil || !matched {
    68→			return false
    69→		}
    70→	}
    71→	if exclude != nil && *exclude != "" {
    72→		matched, err := regexp.MatchString(*exclude, version)
    73→		if err != nil || matched {
    74→			return false
    75→		}
    76→	}
    77→	return true
    78→}
    79→
    80→// Work processes a notify job: fetches the release, resolves subscriptions,
    81→// sends notifications to all matching channels, and checks agent rules to
    82→// auto-trigger agent runs when version criteria are met.
    83→func (w *NotifyWorker) Work(ctx context.Context, job *river.Job[queue.NotifyJobArgs]) error {
    84→	release, err := w.store.GetRelease(ctx, job.Args.ReleaseID)
    85→	if err != nil {
    86→		return fmt.Errorf("get release: %w", err)
    87→	}
    88→
    89→	// Check source version filters — skip entirely if filtered out.
    90→	source, err := w.store.GetSource(ctx, job.Args.SourceID)
    91→	if err != nil {
    92→		return fmt.Errorf("get source: %w", err)
    93→	}
    94→	if !VersionPassesFilter(release.Version, source.VersionFilterInclude, source.VersionFilterExclude) {
    95→		slog.Debug("release filtered by version filter", "version", release.Version, "source_id", job.Args.SourceID)
    96→		return nil
    97→	}
    98→
    99→	// Check exclude_prereleases — skip if source excludes prereleases and this is one.
   100→	if source.ExcludePrereleases {
   101→		var rawData map[string]interface{}
   102→		if err := json.Unmarshal(release.RawData, &rawData); err == nil {
   103→			if prerelease, _ := rawData["prerelease"].(string); prerelease == "true" {
   104→				slog.Debug("release filtered by exclude_prereleases", "version", release.Version, "source_id", job.Args.SourceID)
   105→				return nil
   106→			}
   107→		}
   108→	}
   109→
   110→	// Create a TODO for this release (idempotent — safe for retries).
   111→	todoID, todoErr := w.store.CreateReleaseTodo(ctx, release.ID)
   112→	if todoErr != nil {
   113→		slog.Error("create release todo failed", "release_id", release.ID, "err", todoErr)
   114→		// Continue — notification delivery is primary responsibility.
   115→	}
   116→
   117→	subs, err := w.store.ListSourceSubscriptions(ctx, job.Args.SourceID)
   118→	if err != nil {
   119→		return fmt.Errorf("list subscriptions: %w", err)
   120→	}
   121→
   122→	for _, sub := range subs {
   123→		ch, err := w.store.GetChannel(ctx, sub.ChannelID)
   124→		if err != nil {
   125→			slog.Error("get channel failed", "channel_id", sub.ChannelID, "err", err)
   126→			continue
   127→		}
   128→
   129→		sender, ok := w.senders[ch.Type]
   130→		if !ok {
   131→			slog.Warn("unknown channel type", "type", ch.Type)
   132→			continue
   133→		}
   134→
   135→		// Build title with project name if available.
   136→		title := release.Version
   137→		if release.ProjectName != "" {
   138→			title = release.ProjectName
   139→		}
   140→
   141→		msg := Notification{
   142→			Title:       title,
   143→			Body:        string(release.RawData),
   144→			Version:     release.Version,
   145→			ProjectName: release.ProjectName,
   146→			Provider:    release.Provider,
   147→			Repository:  release.Repository,
   148→			SourceURL:   ProviderURL(release.Provider, release.Repository, release.Version),
   149→		}
   150→		if w.publicURL != "" {
   151→			msg.ReleaseURL = fmt.Sprintf("%s/releases/%s", w.publicURL, release.ID)
   152→		}
   153→		if todoID != "" {
   154→			msg.TodoID = todoID
   155→			msg.PublicURL = w.publicURL
   156→		}
   157→
   158→		if err := sender.Send(ctx, ch, msg); err != nil {
   159→			slog.Error("send notification failed", "channel", ch.Name, "err", err)
   160→		}
   161→	}
   162→
   163→	// Check agent rules and auto-trigger if criteria are met.
   164→	w.checkAgentRules(ctx, release, source)
   165→
   166→	return nil
   167→}
   168→
   169→// checkAgentRules evaluates the project's agent rules against the new release
   170→// and the previous release for this source. If any rule matches, an agent run
   171→// is enqueued. Errors are logged but do not fail the job — notification delivery
   172→// is the primary responsibility.
   173→func (w *NotifyWorker) checkAgentRules(ctx context.Context, release *models.Release, source *models.Source) {
   174→	project, err := w.store.GetProject(ctx, source.ProjectID)
   175→	if err != nil {
   176→		slog.Error("get project for agent rules", "project_id", source.ProjectID, "err", err)
   177→		return
   178→	}
   179→
   180→	// If the project has an active release gate, skip agent rule checking here.
   181→	// The gate worker handles agent triggering.
   182→	hasGate, err := w.store.HasReleaseGate(ctx, source.ProjectID)
   183→	if err != nil {
   184→		slog.Error("check release gate", "project_id", source.ProjectID, "err", err)
   185→		return
   186→	}
   187→	if hasGate {
   188→		slog.Debug("agent rules skipped — project has release gate", "project_id", source.ProjectID)
   189→		return
   190→	}
   191→
   192→	// Parse the project's agent_rules JSON.
   193→	var rules models.AgentRules
   194→	if len(project.AgentRules) > 0 {
   195→		if err := json.Unmarshal(project.AgentRules, &rules); err != nil {
   196→			slog.Error("unmarshal agent rules", "project_id", project.ID, "err", err)
   197→			return
   198→		}
   199→	}
   200→
   201→	// Determine the previous version for comparison.
   202→	var previousVersion string
   203→	prev, err := w.store.GetPreviousRelease(ctx, source.ID, release.Version)
   204→	if err != nil {
   205→		slog.Error("get previous release for agent rules", "source_id", source.ID, "err", err)
   206→		return
   207→	}
   208→	if prev != nil {
   209→		previousVersion = prev.Version
   210→	}
   211→
   212→	if CheckAgentRules(&rules, release.Version, previousVersion) {
   213→		trigger := fmt.Sprintf("auto:version:%s", release.Version)
   214→		if err := w.store.EnqueueAgentRun(ctx, source.ProjectID, trigger, release.Version); err != nil {
   215→			slog.Error("enqueue agent run", "project_id", source.ProjectID, "err", err)
   216→		} else {
   217→			slog.Info("agent run triggered by version rules",
   218→				"project_id", source.ProjectID,
   219→				"version", release.Version,
   220→				"previous_version", previousVersion,
   221→			)
   222→		}
   223→	}
   224→}
