func TestStealthIntegration(t *testing.T) {
	ctx := context.Background()
	store := testStore(t)

	// Set up API server
	broadcaster := api.NewBroadcaster()
	mux := http.NewServeMux()
	api.RegisterRoutes(mux, api.Dependencies{
