func status() {
	home, _ := os.UserHomeDir()
	pidPath := filepath.Join(home, ".changelogue", "stealth.pid")
	data, err := os.ReadFile(pidPath)
	if err != nil {
		fmt.Println("stealth: not running (no PID file)")
		return
	}
	fmt.Printf("stealth: running (PID %s)\n", string(data))
}
