	ctx := context.Background()
	store := testStore(t)

	// Set up API server
	broadcaster := api.NewBroadcaster()
	mux := http.NewServeMux()
	api.RegisterRoutes(mux, api.Dependencies{
		ProjectsStore:         store,
		ReleasesStore:         store,
		SubscriptionsStore:    store,
		SourcesStore:          store,
		ChannelsStore:         store,
		ContextSourcesStore:   ContextSourcesStub{},
