     9→// PollStatusUpdater persists poll status for a source.
    10→type PollStatusUpdater interface {
    11→	UpdateSourcePollStatus(ctx context.Context, id string, pollErr error) error
    12→}
    13→
    14→// Orchestrator runs polling ingestion sources on a fixed interval.
    15→type Orchestrator struct {
    16→	service       *Service
    17→	loader        *SourceLoader
    18→	pollUpdater   PollStatusUpdater
    19→	staticSources []IIngestionSource // for testing only
    20→	interval      time.Duration
    21→}
    22→
    23→// NewOrchestrator creates an orchestrator that dynamically loads enabled
    24→// sources from the database on each poll cycle.
    25→func NewOrchestrator(service *Service, loader *SourceLoader, pollUpdater PollStatusUpdater, interval time.Duration) *Orchestrator {
    26→	return &Orchestrator{service: service, loader: loader, pollUpdater: pollUpdater, interval: interval}
    27→}
    28→
    29→// NewOrchestratorWithSources creates an orchestrator with a static source list.
    30→// Intended for testing; production code should use NewOrchestrator with a SourceLoader.
    31→func NewOrchestratorWithSources(service *Service, sources []IIngestionSource, interval time.Duration) *Orchestrator {
    32→	return &Orchestrator{service: service, staticSources: sources, interval: interval}
    33→}
    34→
    35→// Run polls all sources immediately, then on every tick. Blocks until ctx is cancelled.
    36→func (o *Orchestrator) Run(ctx context.Context) {
    37→	ticker := time.NewTicker(o.interval)
    38→	defer ticker.Stop()
    39→
    40→	o.pollAll(ctx)
    41→
    42→	for {
    43→		select {
    44→		case <-ctx.Done():
    45→			return
    46→		case <-ticker.C:
    47→			o.pollAll(ctx)
    48→		}
    49→	}
    50→}
    51→
    52→func (o *Orchestrator) pollAll(ctx context.Context) {
    53→	sources := o.staticSources
    54→	if sources == nil {
    55→		scheduled, err := o.loader.LoadEnabledSources(ctx)
    56→		if err != nil {
    57→			slog.Error("load sources failed", "err", err)
    58→			return
    59→		}
    60→		if len(scheduled) == 0 {
    61→			slog.Debug("no enabled sources to poll")
    62→			return
    63→		}
    64→		now := time.Now()
    65→		for _, ss := range scheduled {
    66→			if ss.LastPolledAt != nil {
    67→				interval := time.Duration(ss.PollIntervalSeconds) * time.Second
    68→				if now.Before(ss.LastPolledAt.Add(interval)) {
    69→					continue
    70→				}
    71→			}
    72→			o.pollSource(ctx, ss.Source)
    73→		}
    74→		return
    75→	}
    76→	if len(sources) == 0 {
    77→		slog.Debug("no enabled sources to poll")
    78→		return
    79→	}
    80→	for _, src := range sources {
    81→		o.pollSource(ctx, src)
    82→	}
    83→}
    84→
    85→func (o *Orchestrator) pollSource(ctx context.Context, src IIngestionSource) {
    86→	results, err := src.FetchNewReleases(ctx)
    87→	if err != nil {
    88→		slog.Error("poll failed", "source", src.Name(), "err", err)
    89→		o.updateSourcePollStatus(ctx, src.SourceID(), err)
    90→		return
    91→	}
    92→	o.updateSourcePollStatus(ctx, src.SourceID(), nil)
    93→	if len(results) == 0 {
    94→		return
    95→	}
    96→	if err := o.service.ProcessResults(ctx, src.SourceID(), src.Name(), results); err != nil {
    97→		slog.Error("process failed", "source", src.Name(), "err", err)
    98→	}
    99→}
