    28→// List handles GET /releases — returns all releases across all projects.
    29→func (h *ReleasesHandler) List(w http.ResponseWriter, r *http.Request) {
    30→	page, perPage := ParsePagination(r)
    31→	includeExcluded := r.URL.Query().Get("include_excluded") == "true"
    32→	filter := ParseReleaseFilters(r)
    33→	releases, total, err := h.store.ListAllReleases(r.Context(), page, perPage, includeExcluded, filter)
    34→	if err != nil {
    35→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list releases")
    36→		return
    37→	}
    38→	if releases == nil {
    39→		releases = []models.Release{}
    40→	}
    41→	RespondList(w, r, http.StatusOK, releases, page, perPage, total)
    42→}
