    16→// ParseReleaseFilters extracts release filter params from the request query string.
    17→func ParseReleaseFilters(r *http.Request) ReleaseFilter {
    18→	q := r.URL.Query()
    19→	f := ReleaseFilter{
    20→		Provider: q.Get("provider"),
    21→		Urgency:  q.Get("urgency"),
    22→	}
    23→	if v := q.Get("date_from"); v != "" {
    24→		if t, err := time.Parse("2006-01-02", v); err == nil {
    25→			f.DateFrom = &t
    26→		}
    27→	}
    28→	if v := q.Get("date_to"); v != "" {
    29→		if t, err := time.Parse("2006-01-02", v); err == nil {
    30→			end := t.Add(24*time.Hour - time.Nanosecond)
    31→			f.DateTo = &end
    32→		}
    33→	}
    34→	return f
    35→}
